static HeapNode *new_node(int key, HeapNode *parent) {
    HeapNode *node = malloc(sizeof(*node));
    if (node == NULL) return NULL;
    node->key = key; node->left = NULL; node->right = NULL; node->parent = parent;
    return node;
}

HeapNode *heap_insert(HeapNode *root, size_t n, int value) {
    (void)n;
    (void)value;
    /* TODO: follow the binary path for index n + 1, attach the node, and upheap. */
    return root;
}

HeapNode *heap_from_level_order(const int *values, size_t n) {
    if (n == 0) return NULL;
    HeapNode **nodes = calloc(n, sizeof(*nodes));
    if (nodes == NULL) return NULL;
    for (size_t i = 0; i < n; i++) nodes[i] = new_node(values[i], NULL);
    for (size_t i = 0; i < n; i++) {
        size_t left = 2 * i + 1, right = left + 1;
        if (left < n) { nodes[i]->left = nodes[left]; nodes[left]->parent = nodes[i]; }
        if (right < n) { nodes[i]->right = nodes[right]; nodes[right]->parent = nodes[i]; }
    }
    HeapNode *root = nodes[0]; free(nodes); return root;
}

void heap_print_level_order(const HeapNode *root) {
    if (root == NULL) return;
    const HeapNode *queue[128]; size_t first=0, count=0; queue[count++]=root;
    while (first < count) { const HeapNode *node=queue[first++]; printf("%d ", node->key); if(node->left) queue[count++]=node->left; if(node->right) queue[count++]=node->right; }
}
bool heap_parent_links_valid(const HeapNode *root, const HeapNode *parent) { return root == NULL || (root->parent == parent && heap_parent_links_valid(root->left, root) && heap_parent_links_valid(root->right, root)); }
void heap_free(HeapNode *root) { if(root == NULL) return; heap_free(root->left); heap_free(root->right); free(root); }

