#include "heap.h"
#include <stdio.h>
#include <stdlib.h>

static HeapNode *new_node(int key, HeapNode *parent) {
    HeapNode *node = malloc(sizeof(*node));
    if (node == NULL) return NULL;
    node->key = key; node->left = NULL; node->right = NULL; node->parent = parent;
    return node;
}

HeapNode *heap_insert(HeapNode *root, size_t n, int value) {
    if (root == NULL) return new_node(value, NULL);

    const size_t index = n + 1;
    size_t highest_bit = 1;
    while ((highest_bit << 1) <= index) highest_bit <<= 1;

    HeapNode *parent = root;
    for (size_t bit = highest_bit >> 1; bit > 1; bit >>= 1) {
        parent = (index & bit) ? parent->right : parent->left;
    }

    HeapNode *node = new_node(value, parent);
    if (node == NULL) return root;
    if (index & 1) parent->right = node; else parent->left = node;

    while (node->parent != NULL && node->key < node->parent->key) {
        int temp = node->key;
        node->key = node->parent->key;
        node->parent->key = temp;
        node = node->parent;
    }

    return root;
}

